{
  "items": [
    {
      "title": "German Longitudinal Election Study (GLES)",
      "description": "Comprehensive election research program covering German federal elections since 2009; includes pre- and post-election cross-sections, rolling cross-sections, and campaign panels measuring voting behaviour, party preferences, and political attitudes."
    },
    {
      "title": "Politbarometer",
      "description": "Long-running monthly public opinion time series for Germany; tracks vote intention, party ratings, issue salience, government approval, and other political attitudes relevant to elections."
    },
    {
      "title": "European Election Study (EES)",
      "description": "Cross-national post-election surveys for European Parliament elections; covers turnout, vote choice, party evaluations, EU attitudes, and political participation."
    },
    {
      "title": "Eurobarometer",
      "description": "Series of EU public opinion surveys; many waves include modules on political trust, institutions, participation, and electoral behaviour, widely used for research on political attitudes."
    },
    {
      "title": "GESIS Panel",
      "description": "Probability-based longitudinal panel of adults in Germany; includes recurrent modules on political behaviour, civic engagement, trust, and election-related items across multiple waves."
    },
    {
      "title": "ALLBUS (German General Social Survey)",
      "description": "Biennial survey in Germany capturing long-term trends in political attitudes and behaviour, including party identification, political efficacy, trust, participation, and past voting behaviour."
    },
    {
      "title": "GLES 2017 Rolling Cross-Section",
      "description": "Daily interviews across the 2017 Bundestag election campaign measuring short-term campaign dynamics in vote intention, party evaluations, and political attitudes."
    },
    {
      "title": "GLES 2021 Rolling Cross-Section",
      "description": "Daily campaign-period interviews for the 2021 Bundestag election analysing dynamics of vote choice, issue emphasis, and political attitudes."
    },
    {
      "title": "European Election Study 2014 Voter Study",
      "description": "Post-election survey after the 2014 European Parliament election focusing on voter behaviour, turnout, party choice, and attitudes toward the EU."
    },
    {
      "title": "German Bundestag Election Study 1998",
      "description": "Election study of the 1998 federal election in Germany examining voter behaviour, campaign effects, and political attitudes."
    }
  ]
}
